    def resolve_products(parent, info, id=None, sku=None, category_id=None, search=None, limit=None, offset=None):
        items = PRODUCTS[:]
        if id is not None:
            items = [p for p in items if p["id"] == id]
        if sku is not None:
            items = [p for p in items if p["sku"] == sku]
        if category_id is not None:
            items = [p for p in items if p["category_id"] == category_id]
        if search is not None:
            s = search.strip().lower()
            if s:
                items = [p for p in items if s in p["name"].lower() or s in p["sku"].lower()]
        offset = offset or 0
        if offset:
            items = items[offset:]
        if limit is not None:
            items = items[: max(0, limit)]
        return items

    def resolve_product(parent, info, id):
        return _get_product_by_id(id)

